// Precio promedio bolsa nacional XM últimos N días.
// XM cambia MetricId y endpoint con frecuencia. Probamos múltiples candidatos.
const src = $input.first().json;
const body = src.body || src;
const daysBack = Math.min(Math.max(parseInt(body.days ?? 30, 10) || 30, 1), 90);

const XM_BASE = 'https://servapibi.xm.com.co';
const isoDate = d => d.toISOString().slice(0, 10);
const endDate = new Date(Date.now() - 24 * 60 * 60 * 1000); // T-1 (XM publica con delay)
const startDate = new Date(endDate.getTime() - daysBack * 24 * 60 * 60 * 1000);

const postXM = async (path, reqBody) => {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `${XM_BASE}${path}`,
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'User-Agent': 'alebas-cotizador/1.0' },
    body: JSON.stringify(reqBody),
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
  if (r.statusCode === 400 || r.statusCode === 404 || r.statusCode === 422) {
    const e = new Error(`XM ${path} HTTP ${r.statusCode}`);
    e.clientError = true;
    throw e;
  }
  if (r.statusCode >= 500) throw new Error(`XM ${path} HTTP ${r.statusCode}`);
  return typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
};

// Candidatos en orden de probabilidad según historial de cambios de XM 2023-2025.
const CANDIDATES = [
  { path: '/hourly', MetricId: 'Preciobols',      Entity: 'Sistema' },
  { path: '/hourly', MetricId: 'PrecBolsNal',     Entity: 'Sistema' },
  { path: '/hourly', MetricId: 'PrecioBolsaNal',  Entity: 'Sistema' },
  { path: '/hourly', MetricId: 'PreciosBolsa',    Entity: 'Sistema' },
  { path: '/hourly', MetricId: 'Bolsa',           Entity: 'Sistema' },
  { path: '/hourly', MetricId: 'PrecBolsNal',     Entity: 'SIN'     },
  { path: '/hourly', MetricId: 'Preciobols'                          },
  { path: '/hourly', MetricId: 'PrecBolsNal'                         },
  { path: '/daily',  MetricId: 'Preciobols',      Entity: 'Sistema' },
  { path: '/daily',  MetricId: 'PrecBolsNal',     Entity: 'Sistema' },
  { path: '/daily',  MetricId: 'Bolsa',           Entity: 'Sistema' },
  { path: '/monthly', MetricId: 'Preciobols',     Entity: 'Sistema' },
  { path: '/monthly', MetricId: 'PrecBolsNal',    Entity: 'Sistema' },
];

let rawJson = null;
let usedLabel = '';
const tried = [];
for (const c of CANDIDATES) {
  const reqBody = { MetricId: c.MetricId, StartDate: isoDate(startDate), EndDate: isoDate(endDate) };
  if (c.Entity) reqBody.Entity = c.Entity;
  const label = `${c.path}/${c.MetricId}${c.Entity ? '/'+c.Entity : ''}`;
  tried.push(label);
  try {
    rawJson = await postXM(c.path, reqBody);
    usedLabel = label;
    break;
  } catch (err) {
    if (err.clientError) continue;
    return [{ json: { ok: false, reason: 'upstream_error', detail: err.message } }];
  }
}

if (!rawJson) {
  return [{ json: { ok: false, reason: 'xm_schema_drift', detail: `Ningún candidato respondió`, tried } }];
}

// Extractor recursivo: recoge valores numéricos en claves Hour##/Hora##/Value##/Precio/Price/Total.
const values = [];
const walk = (node) => {
  if (node == null) return;
  if (Array.isArray(node)) { node.forEach(walk); return; }
  if (typeof node === 'object') {
    for (const [k, v] of Object.entries(node)) {
      if (/^(Hour|Hora|Value|Precio|Price|Total)\d{0,2}$/i.test(k) && Number.isFinite(Number(v)) && Number(v) > 0) {
        values.push(Number(v));
      } else if (typeof v === 'object') {
        walk(v);
      }
    }
  }
};
walk(rawJson);

if (!values.length) {
  return [{ json: { ok: false, reason: 'xm_schema_drift', detail: `Respuesta sin datos (métrica: ${usedLabel})`, sample: rawJson } }];
}

const avgMwh = values.reduce((s, v) => s + v, 0) / values.length;
return [{ json: {
  ok: true,
  cop_per_kwh:     Number((avgMwh / 1000).toFixed(2)),
  avg_cop_per_mwh: Number(avgMwh.toFixed(2)),
  samples:         values.length,
  periodDays:      daysBack,
  startDate:       isoDate(startDate),
  endDate:         isoDate(endDate),
  usedMetric:      usedLabel,
  syncedAt:        new Date().toISOString(),
  source:          `XM ${usedLabel}`,
} }];
